customCSS:
/* Pixel Arcade — INSERT COIN */
@import url('https://fonts.googleapis.com/css2?family=Press+Start+2P&family=Share+Tech+Mono&display=swap');

.cyber-grid {
  background:
    linear-gradient(transparent 0%, transparent 96%, rgba(0, 170, 255, 0.06) 97%, rgba(0, 170, 255, 0.06) 100%),
    linear-gradient(90deg, transparent 0%, transparent 96%, rgba(0, 170, 255, 0.06) 97%, rgba(0, 170, 255, 0.06) 100%);
  background-size: 20px 20px;
  animation: none;
}

.cyber-glow {
  background:
    radial-gradient(ellipse 400px 250px at 50% 0%, rgba(0, 170, 255, 0.08), transparent),
    radial-gradient(ellipse 300px 200px at 50% 100%, rgba(0, 255, 0, 0.06), transparent);
}

.stat-card {
  border: 2px solid rgba(0, 170, 255, 0.3);
  backdrop-filter: none;
}

.stat-card::before {
  background: linear-gradient(90deg, #ff0000, #ffff00, #00ff00, #00aaff, #ff00ff);
  height: 3px;
}

.stat-card:hover {
  border-color: rgba(0, 255, 0, 0.5);
  box-shadow: 0 0 15px rgba(0, 255, 0, 0.2);
}

.stat-value {
  text-shadow: 0 0 6px currentColor;
  letter-spacing: 2px;
}

.celebration-title {
  background: linear-gradient(180deg, #ffff00, #ff6600, #ff0000);
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
  text-shadow: none;
}

.miner-card, .health-card, .lifetime-card {
  border: 2px solid rgba(0, 170, 255, 0.15);
}

.miner-card:hover {
  border-color: rgba(0, 255, 0, 0.3);
}

.logo {
  color: #00ff00;
  text-shadow: 2px 2px 0 #005500;
  letter-spacing: 3px;
}
